1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote — base premiums", () => {
6	    it("returns 5G processing fee for an empty item list", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it.todo("computes base premium for a single sword (100G + 5G fee)");
14	    it.todo("computes base premium for a single amulet (60G + 5G fee)");
15	    it.todo("computes base premium for a single staff (80G + 5G fee)");
16	    it.todo("computes base premium for a single potion (40G + 5G fee)");
17	    it.todo("computes base premium for a single component (25G + 5G fee)");
18	    it.todo("computes base premium for multiple items (sword + amulet = 160G + 5G fee)");
19	  });
20	
21	  describe("Quote — component block pricing", () => {
22	    it.todo("prices 2 runes at 50G (no block)");
23	    it.todo("prices 3 alike runes at 60G (block of 3)");
24	    it.todo("prices 4 runes at 100G (no block — block requires exactly 3)");
25	    it.todo("prices 3 runes + 3 moonstones at 120G (two separate blocks)");
26	    it.todo("does not apply block for 2 runes + 1 moonstone (different types)");
27	  });
28	
29	  describe("Quote — item-level modifiers", () => {
30	    it.todo("adds 50% cursed surcharge to the cursed item only");
31	    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
32	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
33	    it.todo("does not apply high-enchantment surcharge for enchantment 4");
34	    it.todo("item-level modifiers apply only to the affected item in a multi-item policy");
35	  });
36	
37	  describe("Quote — policy-level modifiers", () => {
38	    it.todo("adds 10% first-insurance surcharge on the policy base premium");
39	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
40	    it.todo("applies 15% follow-up discount on second and subsequent quotes");
41	    it.todo("applies all policy-level modifiers together (loyalty + first insurance + follow-up)");
42	  });
43	
44	  describe("Quote — rounding", () => {
45	    it.todo("rounds premium up (ceil) in MHPCO's favor");
46	  });
47	
48	  describe("Quote — integration", () => {
49	    it.todo("newcomer with cursed sword: 165G");
50	    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
51	  });
52	
53	  describe("Quote — errors", () => {
54	    it.todo("throws error for unknown item type");
55	  });
56	
57	  describe("Claim — basic reimbursement", () => {
58	    it.todo("reimburses damage minus 100G deductible for a standard item");
59	    it.todo("reimburses damage to a component minus 100G deductible");
60	    it.todo("applies deductible per damaged item in a multi-item claim");
61	  });
62	
63	  describe("Claim — enchantment and material clauses", () => {
64	    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
65	    it.todo("reimburses fully for dragon-material items, then deductible");
66	    it.todo("applies 50% rule when both dragon-material and enchantment >= 8");
67	    it.todo("dragon-material with enchantment < 8 gets full reimbursement minus deductible");
68	  });
69	
70	  describe("Claim — cap", () => {
71	    it.todo("caps total payout at 2x insurance sum");
72	    it.todo("tracks remaining cap across successive claims");
73	    it.todo("cap is based on unmodified insurance values, not premiums");
74	  });
75	
76	  describe("Claim — payout rounding", () => {
77	    it.todo("rounds payout down (floor) in MHPCO's favor");
78	  });
79	
80	  describe("Claim — errors", () => {
81	    it.todo("throws error when damage references an item not in the policy");
82	    it.todo("throws error when more damages of a type than insured items");
83	    it.todo("throws error for negative damage amount");
84	  });
85	});
